class Solution:
    def stoneGameVIII(self, stones):
        n = len(stones)
        p = stones[:]
        for i in range(1, n):
            p[i] += p[i - 1]
        dp = p[n - 1]
        for i in range(n - 2, 0, -1):
            dp = max(dp, p[i] - dp)
        return dp

