var stoneGameVIII = function(stones) {
    const n = stones.length;
    const p = stones.slice();
    for (let i = 1; i < n; i++) p[i] += p[i - 1];
    let dp = p[n - 1];
    for (let i = n - 2; i >= 1; i--) dp = Math.max(dp, p[i] - dp);
    return dp;
};
